'use client';

import { useAuth } from '@/components/auth-provider';
import { useRouter } from 'next/navigation';
import { useEffect, useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';

export default function AdminDashboardPage() {
  const { user, loading, hasPermission } = useAuth();
  const router = useRouter();
  const [bgmUrl, setBgmUrl] = useState('');
  const [logBgUrl, setLogBgUrl] = useState('');
  const [isSavingBgm, setIsSavingBgm] = useState(false);

  useEffect(() => {
    if (!loading) {
      if (!user) {
        alert('로그인이 필요합니다.');
        router.push('/login');
      } else if (!hasPermission(['SUPER_ADMIN', 'ADMIN', 'EDITOR', 'MANAGER'])) {
        alert('관리자 권한이 없습니다.');
        router.push('/');
      } else if (hasPermission(['SUPER_ADMIN', 'ADMIN'])) {
        // 설정 정보 불러오기
        fetch('/api/settings').then(res => res.json()).then(data => {
          if (data && data.bgmUrl !== undefined) setBgmUrl(data.bgmUrl);
          if (data && data.logBgUrl !== undefined) setLogBgUrl(data.logBgUrl);
        }).catch(err => console.error(err));
      }
    }
  }, [user, loading, router, hasPermission]);

  const handleSaveBgm = async () => {
    setIsSavingBgm(true);
    try {
      const res = await fetch('/api/settings', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ bgmUrl, logBgUrl })
      });
      if (res.ok) {
        toast.success('BGM 설정이 저장되었습니다. 새로고침 후 반영됩니다.');
      } else {
        toast.error('설정 저장 실패');
      }
    } catch {
      toast.error('설정 저장 중 오류가 발생했습니다.');
    } finally {
      setIsSavingBgm(false);
    }
  }

  if (loading || !user) {
    return <div className="p-8 text-center min-h-[50vh]">로딩 중...</div>;
  }

  return (
    <div className="container mx-auto px-4 py-8">
      <h1 className="text-3xl font-bold mb-6">관리자 대시보드</h1>
      <p className="mb-8 text-muted-foreground">환영합니다! 권한: {user.role}</p>

      <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
        <Card>
          <CardHeader>
            <CardTitle>공지사항/설정관리</CardTitle>
            <CardDescription>전체 웹사이트 관련 옵션 (Youtube BGM 포함)</CardDescription>
          </CardHeader>
          <CardContent>
            {hasPermission(['SUPER_ADMIN', 'ADMIN']) ? (
              <div className="space-y-4">
                <div className="space-y-2">
                  <label className="text-sm font-medium">유튜브 BGM 링크</label>
                  <div className="flex gap-2">
                    <Input 
                      placeholder="예. https://www.youtube.com/watch?v=..." 
                      value={bgmUrl}
                      onChange={(e) => setBgmUrl(e.target.value)}
                    />
                  </div>
                  <p className="text-xs text-muted-foreground">유튜브 영상 링크를 넣으면 네비게이션 음악 재생기로 자동 연동됩니다.</p>
                </div>
                
                <div className="space-y-2 pt-2 border-t">
                  <label className="text-sm font-medium">Log 게시판 배경 이미지 URL</label>
                  <div className="flex gap-2">
                    <Input 
                      placeholder="예. https://example.com/image.jpg" 
                      value={logBgUrl}
                      onChange={(e) => setLogBgUrl(e.target.value)}
                    />
                  </div>
                  <p className="text-xs text-muted-foreground">Log 페이지의 전체 배경으로 표시될 이미지 주소를 입력하세요.</p>
                </div>

                <Button disabled={isSavingBgm} onClick={handleSaveBgm} className="w-full mt-4">설정 저장</Button>
              </div>
            ) : (
              <p className="text-red-500">권한 부족</p>
            )}
          </CardContent>
        </Card>
        
        <Card>
          <CardHeader>
            <CardTitle>캐릭터 및 갤러리 관리</CardTitle>
            <CardDescription>홈페이지 내 캐릭터 추가 및 삭제</CardDescription>
          </CardHeader>
          <CardContent>
            {hasPermission(['SUPER_ADMIN', 'ADMIN', 'MANAGER']) ? (
              <p>캐릭터 수정 및 업로드가 가능합니다.</p>
            ) : (
              <p className="text-red-500">권한 부족</p>
            )}
          </CardContent>
        </Card>
        
        <Card>
          <CardHeader>
            <CardTitle>게시글(Board, Log) 편집</CardTitle>
            <CardDescription>사용자가 올린 게시글 관리</CardDescription>
          </CardHeader>
          <CardContent>
            {hasPermission(['SUPER_ADMIN', 'ADMIN', 'MANAGER', 'EDITOR']) ? (
              <p>편집자 권한으로 게시글을 수정 및 삭제할 수 있습니다.</p>
            ) : (
              <p className="text-red-500">권한 부족</p>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}
